import{_ as o,o as r,c as a,a2 as e}from"./chunks/framework.Crpw6aS5.js";const g=JSON.parse('{"title":"1976年 核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1976年/核心总结.md","filePath":"01_letters/1976年/核心总结.md"}'),l={name:"01_letters/1976年/核心总结.md"};function n(d,t,i,s,h,p){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="_1976年-核心总结" tabindex="-1">1976年 核心总结 <a class="header-anchor" href="#_1976年-核心总结" aria-label="Permalink to &quot;1976年 核心总结&quot;">​</a></h1><blockquote><p><strong>一句话总结：</strong> 从谷底强势反弹！营业利润1607万美元创历史新高，ROE 17.3%，保险承保利润率大幅改善。菲尔·利舍领导的国民赔偿保险，是这次反弹的核心引擎。</p></blockquote><h2 id="核心数据" tabindex="-1">核心数据 <a class="header-anchor" href="#核心数据" aria-label="Permalink to &quot;核心数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>1976年</th><th>对比</th></tr></thead><tbody><tr><td>营业利润</td><td><strong>1607万美元</strong></td><td>历史新高！</td></tr><tr><td>每股收益</td><td><strong>$16.47</strong></td><td>历史新高！</td></tr><tr><td>ROE</td><td><strong>17.3%</strong></td><td>从7.6%强势反弹</td></tr><tr><td>保险综合赔付率</td><td><strong>降至98.7%</strong></td><td>从115.4大幅改善</td></tr><tr><td>本土州保费增长</td><td><strong>+78%</strong></td><td>爆发式增长</td></tr></tbody></table><h2 id="全面复苏的三大引擎" tabindex="-1">全面复苏的三大引擎 <a class="header-anchor" href="#全面复苏的三大引擎" aria-label="Permalink to &quot;全面复苏的三大引擎&quot;">​</a></h2><h3 id="_1-保险承保-核心反弹" tabindex="-1">① 保险承保：核心反弹 <a class="header-anchor" href="#_1-保险承保-核心反弹" aria-label="Permalink to &quot;① 保险承保：核心反弹&quot;">​</a></h3><p>菲尔·利舍（Phil Liesche）接替杰克·林沃尔特后的第一个完整年度，交出了出色答卷：</p><table tabindex="0"><thead><tr><th>业务板块</th><th>1975年赔付率</th><th>1976年赔付率</th></tr></thead><tbody><tr><td>行业整体汽车险</td><td>113.5</td><td>107.4</td></tr><tr><td>国民赔偿保险整体</td><td>115.4</td><td><strong>98.7</strong></td></tr></tbody></table><blockquote><p>&quot;我们自身的改善幅度，远超行业平均水平。&quot;</p></blockquote><p>三大功臣：</p><ul><li><strong>菲尔·利舍</strong>：国民赔偿保险核心业务，承保纪律的守护者</li><li><strong>罗兰·米勒</strong>：承保部门负责人</li><li><strong>比尔·莱昂斯</strong>：理赔部门负责人</li></ul><h3 id="_2-本土州保险-78-爆发增长" tabindex="-1">② 本土州保险：78%爆发增长 <a class="header-anchor" href="#_2-本土州保险-78-爆发增长" aria-label="Permalink to &quot;② 本土州保险：78%爆发增长&quot;">​</a></h3><p>本土州模式经过五年探索，1976年迎来爆发：</p><ul><li>综合成本率从108.4降至<strong>102.7</strong></li><li>内布拉斯加玉米壳意外伤害保险公司：综合成本率<strong>94.4</strong>（历史新低，第六年第五次低于100）</li><li>德克萨斯联合保险公司：获年度&quot;董事长杯&quot;</li><li>整体保费收入增长<strong>78%</strong></li></ul><p>巴菲特明确说：本土州业务&quot;具有重大长期潜力&quot;。</p><h3 id="_3-家庭汽车保险公司-强势复苏" tabindex="-1">③ 家庭汽车保险公司：强势复苏 <a class="header-anchor" href="#_3-家庭汽车保险公司-强势复苏" aria-label="Permalink to &quot;③ 家庭汽车保险公司：强势复苏&quot;">​</a></h3><p>约翰·苏厄德（John Seward）在接任后的第一个完整年度，全面改革了公司：</p><ul><li>改为6个月期直接账单保单（更灵活调整费率）</li><li>扩展一般责任险业务</li><li>公司整体实现强劲复苏</li></ul><p>巴菲特评价：&quot;我们对约翰·苏厄德所取得的进展感到非常满意。&quot;</p><h2 id="银行业务-持续书写传奇" tabindex="-1">银行业务：持续书写传奇 <a class="header-anchor" href="#银行业务-持续书写传奇" aria-label="Permalink to &quot;银行业务：持续书写传奇&quot;">​</a></h2><p>Gene Abegg 继续执掌伊利诺伊国民银行，用数据说话：</p><blockquote><p>&quot;克利夫兰国民城市集团在广告中称，1976年其盈利/平均资产比率约为1.34%，在所有大型银行中位居榜首。但伊利诺伊国民银行的这一指标较其高出近<strong>50%</strong>，接近2%。&quot;</p></blockquote><p>三个不变：</p><ol><li>支付最高法定利率（定期存款已占存款基数的2/3以上）</li><li>保持极高流动性（活期存款的等量现金在手）</li><li>规避高收益但资质不佳的贷款（全年贷款净损失仅1.2万美元，占余额的0.02%）</li></ol><p>成本控制：存款规模从3000万→9000万，但员工数量与1969年持平。</p><h2 id="股票投资-开始收获的季节" tabindex="-1">股票投资：开始收获的季节 <a class="header-anchor" href="#股票投资-开始收获的季节" aria-label="Permalink to &quot;股票投资：开始收获的季节&quot;">​</a></h2><p>年报透露了巴菲特对股票组合的长期态度：</p><blockquote><p>&quot;截至年末，我们持有的权益类资产未实现增值达4570万美元，而截至3月21日，这一数值已回落了约500万美元。但这一点同样无关紧要，因为所投资公司的年度经营进展才是至关重要的。&quot;</p></blockquote><p>1976年，公司实现税前996.2万美元的已实现资本利得。这表明：股票组合不仅熬过了1973-1974年熊市，还在持续为公司创造价值。</p><h2 id="重要人事变动" tabindex="-1">重要人事变动 <a class="header-anchor" href="#重要人事变动" aria-label="Permalink to &quot;重要人事变动&quot;">​</a></h2><p><strong>菲尔·利舍升任核心</strong></p><p>这是菲尔·利舍接任杰克·林沃尔特后的第一个完整年度。他主导了国民赔偿保险从1975年灾难（赔付率115.4）到1976年盈利（赔付率98.7）的逆转。</p><p>巴菲特的信任在年报中表露无遗：三位核心管理者并列出现，而菲尔·利舍排在首位。</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><p><strong>洞察一：周期底部坚持原则，周期顶部收获果实</strong></p><p>1974-1975年保险危机期间，伯克希尔的竞争对手纷纷用低价抢单来维持规模，伯克希尔却主动收缩。当1976年费率回升时，坚守纪律的保险公司获得了最大份额的优质业务。</p><p><strong>洞察二：伯克希尔的文化是&quot;结果说话&quot;</strong></p><p>1976年菲尔·利舍的出色表现，让他在年报中被大篇幅称赞。而1975年表现不佳的管理者（佛罗里达市场团队）则被替换。结果好的管理者得到更多资源，结果差的管理者被调整。</p><p><strong>洞察三：17.3% ROE，但低于历史最高</strong></p><p>1972年ROE为19.8%。1976年虽然绝对收益创历史新高，但ROE仍低于1972年。巴菲特的解释：&quot;在持续扩大的权益基数下，ROE下降是正常的。&quot;</p><p>他追求的不是ROE数字的峰值，而是<strong>长期持续的超额回报</strong>。</p><p><strong>洞察四：喜诗糖果的长期价值被低估</strong></p><p>1976年巴菲特再次提到蓝筹印花持有的喜诗糖果。此时喜诗糖果的贡献已相当可观，而它的全部潜力，在未来20年才真正被释放（最终成为伯克希尔旗下最具传奇色彩的盈利来源之一）。</p><h2 id="历史坐标" tabindex="-1">历史坐标 <a class="header-anchor" href="#历史坐标" aria-label="Permalink to &quot;历史坐标&quot;">​</a></h2><ul><li>距离1956年巴菲特合伙基金：<strong>20年</strong></li><li>距离1965年接手伯克希尔：<strong>11年</strong></li><li><strong>完全走出了1973-1974年熊市的影响</strong>，伯克希尔帝国的基础更加牢固</li><li>距离1979年剥离银行资产：<strong>3年</strong>（1980年12月31日前需完成）</li></ul>',45)])])}const q=o(l,[["render",n]]);export{g as __pageData,q as default};
